class Solution:
    def minKBitFlips(self, nums, k):
        a = nums[:]
        n = len(a)
        flips = 0
        for i in range(n):
            if a[i] == 0:
                if i + k > n:
                    return -1
                for j in range(i, i + k):
                    a[j] ^= 1
                flips += 1
        return flips

