var minKBitFlips = function(nums, k) {
    const n = nums.length;
    const diff = new Array(n + 1).fill(0);
    let active = 0, flips = 0;
    for (let i = 0; i < n; i++) {
        active += diff[i];
        if ((nums[i] + active) % 2 === 0) {
            if (i + k > n) return -1;
            flips++;
            active++;
            diff[i + k] -= 1;
        }
    }
    return flips;
};
